sql:
SELECT COUNT(player_id)
FROM players
WHERE pro_bowl_appearances = 0;

SELECT COUNT(DISTINCT p.team_id) AS team_count
FROM players p
WHERE p.player_name = 'Ezekiel Elliott';

external_knowledge:
- 'wounded in the heat of their last 3 battles' refers to players who have been injured in their last 3 games, where an injury is represented by an entry in the `player_injuries` table with a status other than 'Active';
- 'recovering' refers to players whose most recent injury record shows an injury status of 'Active' before the most recent game;
- 'emerged unscathed' refers to players who do not have any injury records within the last 3 games;
- 'already healed' refers to players whose most recent injury status is 'Active'.
